sql:
SELECT target_id, strand 
FROM targets 
WHERE status = 'active' AND inverse_specificity > 0.95;

SELECT COUNT(*)
FROM target_versions
WHERE target_id = 1 AND status = 'approved';

SELECT project_id, COUNT(target_id) AS target_count
FROM project_targets
GROUP BY project_id;

SELECT u.user_name, p.project_name
FROM users u
JOIN projects p ON u.user_id = p.created_by;

SELECT DISTINCT u.user_name
FROM users u
INNER JOIN targets t ON u.user_id = t.created_by;

SELECT project_id, COUNT(DISTINCT target_id) AS distinct_target_count
FROM project_targets
GROUP BY project_id;

external_knowledge:
- 'ongoing targets' refers to 'active status' targets;
- 'sequences on both strands' refers to sequences on the positive and negative strands;
- 'species involved' refers to the species from which the target sequences are derived.

- "ongoing projects" refers to entries in the `targets` table with the status 'active';
- "certain senior member" refers to 'Bob Williams' whose unique identifier is found in the `users` table;
- "initiated by" indicates the targets were created by this user, as indicated by the `created_by` field in the `targets` table.

sql:
SELECT COUNT(*) AS active_sequences
FROM targets t
WHERE t.created_by = (SELECT user_id FROM users WHERE user_name = 'Bob Williams') AND t.status = 'active';
